template:
// 三个不同厂家的传感器，三种数据格式
string raw1 = "85.5°C";        // 松下：去掉末尾的 °C
string raw2 = "TEMP:32.0";     // 西门子：冒号后面才是数字
string raw3 = "temp=28.7C";    // 杂牌：等号后面，C前面

// TODO 1: 处理 raw1 — 用 Replace 把 "°C" 替换成空字符串 ""，再 Parse



// TODO 2: 处理 raw2 — 用 Split(':') 按冒号切开，取第二部分 [1]，再 Parse



// TODO 3: 处理 raw3 — 用 Replace("temp=","").Replace("C","")，再 Parse



// TODO 4: 把三个解析后的数字 Print 出来

hints.text:
string raw1 = "85.5°C";
string raw2 = "TEMP:32.0";
string raw3 = "temp=28.7C";
double t1 = double.Parse(raw1.Replace("°C", ""));
double t2 = double.Parse(raw2.Split(':')[1]);
double t3 = double.Parse(raw3.Replace("temp=", "").Replace("C", ""));
Print($"传感器1: {t1}°C");
Print($"传感器2: {t2}°C");
Print($"传感器3: {t3}°C");
